{
  "guidedPractice": {
    "title": "Guided Practice: Selecting the Correct Instrument for Resistance",
    "objective": "Support the learner in matching circuit parameters to their corresponding measuring instruments using a step-by-step selection process.",
    "retrievalTextLines": [
      "Scenario: You have a heating element that is not working. You need to check the 'opposition to flow' within the element while it is disconnected from the power supply.",
      "Step 1: Identify the electrical quantity. You are measuring the 'opposition to flow'. This quantity is called resistance.",
      "Step 2: Link the quantity to its unit. The unit for resistance is the Ohm (Ω).",
      "Step 3: Select the appropriate instrument based on the unit."
    ],
    "questionText": "Following the steps above, name the specific instrument required to measure the resistance of the heating element.",
    "answerGuidance": [
      "Ohmmeter"
    ],
    "hint": "Think: Ohms = Ohmmeter."
  },
  "practice": {
    "title": "Practice: Identifying Measurement Tools",
    "objective": "Verify the learner can independently select the correct instrument for electrical power without prompts.",
    "retrievalTextLines": [
      "Scenario: You are tasked with measuring the 'rate of electrical power' being used by a large industrial motor while it is running under full load.",
      "To do this correctly, you must select the instrument designed to measure the instantaneous rate of work being done in the circuit."
    ],
    "questionText": "Which specific instrument is used to measure the electrical power (measured in Watts) used by the motor?",
    "answerGuidance": [
      "Wattmeter"
    ],
    "hint": "Don't confuse the rate of power (Watts) with the total energy consumed over time (kWh)."
  }
}

